import secrets
from fastapi import FastAPI, Cookie, HTTPException, Header, Response

app = FastAPI()
SESSIONS: dict[str, dict] = {}  # in production: Redis or DB

@app.post("/auth/login")
def login(response: Response):
    session_id = secrets.token_urlsafe(32)
    csrf_token = secrets.token_urlsafe(32)
    SESSIONS[session_id] = {"user": "alice", "csrf": csrf_token}
    response.set_cookie(
        "session_id", session_id,
        httponly=True,      # not readable by JavaScript — prevents XSS theft
        secure=True,        # HTTPS only
        samesite="lax",     # blocks most CSRF without tokens
    )
    # CSRF token is readable by JS (not httponly) so it can be sent as a header
    response.set_cookie("csrf_token", csrf_token, secure=True, samesite="lax")
    return {"message": "logged in"}

@app.post("/api/run-agent")
def run_agent(
    session_id: str = Cookie(default=None),
    x_csrf_token: str = Header(default=None),
):
    session = SESSIONS.get(session_id or "")
    if not session:
        raise HTTPException(status_code=401, detail="Not authenticated")
    if x_csrf_token != session["csrf"]:
        raise HTTPException(status_code=403, detail="CSRF token mismatch")
    return {"result": f"agent ran for {session['user']}"}

// Browser: read CSRF token from cookie and echo as header
function getCookie(name) {
  const match = document.cookie.match(new RegExp('(^| )' + name + '=([^;]+)'));
  return match ? decodeURIComponent(match[2]) : null;
}

async function runAgent(prompt) {
  const csrfToken = getCookie("csrf_token");  // readable (not httponly)
  const resp = await fetch("/api/run-agent", {
    method: "POST",
    credentials: "include",                    // send session_id cookie
    headers: {
      "Content-Type": "application/json",
      "X-CSRF-Token": csrfToken,              // echoed back to prove same-origin
    },
    body: JSON.stringify({ prompt }),
  });
  return resp.json();
}

